# test_final_state.py
import os
import time
import subprocess
import pytest

def test_script_exists_and_executable():
    script_path = "/home/user/analyze.sh"
    assert os.path.isfile(script_path), f"Script {script_path} does not exist."
    assert os.access(script_path, os.X_OK), f"Script {script_path} is not executable."

def test_execution_time_and_accuracy():
    script_path = "/home/user/analyze.sh"
    output_csv = "/home/user/complexity_scores.csv"
    rust_dir = "/home/user/rust_project"

    # Remove existing output to ensure it's generated by our run
    if os.path.exists(output_csv):
        os.remove(output_csv)

    # Measure execution time
    start_time = time.time()
    result = subprocess.run([script_path], capture_output=True, text=True)
    end_time = time.time()
    execution_time = end_time - start_time

    assert result.returncode == 0, f"Script failed with return code {result.returncode}.\nStderr: {result.stderr}"
    assert os.path.isfile(output_csv), f"Output file {output_csv} was not generated."

    # Assert execution time threshold
    assert execution_time <= 3.0, f"Execution time {execution_time:.2f}s exceeded the 3.0s threshold."

    # Generate expected output
    expected = []
    files = sorted(os.listdir(rust_dir))
    for file in files:
        if not file.endswith(".rs"):
            continue
        with open(os.path.join(rust_dir, file)) as f:
            lines = f.readlines()
            # Parse metadata based on known format
            l = int(lines[1].split(":")[1].strip())
            v = int(lines[2].split(":")[1].strip())
            func = int(lines[3].split(":")[1].strip())
            score = (l * l + v * func) % 10007
            expected.append(f"{file},{score}\n")

    # Read generated output
    with open(output_csv) as f:
        actual = f.readlines()

    assert len(actual) == len(expected), f"Output CSV has {len(actual)} lines, expected {len(expected)}."

    for i, (act, exp) in enumerate(zip(actual, expected)):
        assert act.strip() == exp.strip(), f"Mismatch at line {i + 1}:\nExpected: {exp.strip()}\nActual: {act.strip()}"